import{_ as o,o as a,c as i,ae as t}from"./chunks/framework.BD9pLfSD.js";const m=JSON.parse('{"title":"Modos de Ejecución","description":"","frontmatter":{},"headers":[],"relativePath":"es/docs/modes.md","filePath":"es/docs/modes.md"}'),r={name:"es/docs/modes.md"};function n(l,e,s,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="modos-de-ejecucion" tabindex="-1">Modos de Ejecución <a class="header-anchor" href="#modos-de-ejecucion" aria-label="Permalink to &quot;Modos de Ejecución&quot;">​</a></h1><p>Los agentes xB77 utilizan cuatro niveles de ejecución distintos para equilibrar costo, velocidad y privacidad estratégica.</p><h2 id="nivel-1-fiat-directo-starpay" tabindex="-1">Nivel 1: Fiat Directo (Starpay) <a class="header-anchor" href="#nivel-1-fiat-directo-starpay" aria-label="Permalink to &quot;Nivel 1: Fiat Directo (Starpay)&quot;">​</a></h2><ul><li><strong>Cuándo:</strong> Bajo riesgo, proveedores confiables (ej., AWS, OpenAI).</li><li><strong>Proceso:</strong> El agente utiliza una liquidación mediante tarjeta virtual off-chain.</li><li><strong>Privacidad:</strong> Visible públicamente como una transacción de tarjeta tradicional (Riel Web2).</li><li><strong>Costo:</strong> Bajo (Comisiones de tarjeta estándar).</li></ul><h2 id="nivel-2-transferencia-protegida-light-protocol" tabindex="-1">Nivel 2: Transferencia Protegida (Light Protocol) <a class="header-anchor" href="#nivel-2-transferencia-protegida-light-protocol" aria-label="Permalink to &quot;Nivel 2: Transferencia Protegida (Light Protocol)&quot;">​</a></h2><ul><li><strong>Cuándo:</strong> Operaciones B2B estándar con entidades on-chain.</li><li><strong>Proceso:</strong> Los fondos se mueven dentro del pool privado comprimido por ZK.</li><li><strong>Privacidad:</strong> El monto y el destinatario están ocultos para los scanners públicos.</li><li><strong>Costo:</strong> Medio (Comisiones de relayer y verificación ZK).</li></ul><h2 id="nivel-3-modo-fantasma-relay-efimero" tabindex="-1">Nivel 3: Modo Fantasma (Relay Efímero) <a class="header-anchor" href="#nivel-3-modo-fantasma-relay-efimero" aria-label="Permalink to &quot;Nivel 3: Modo Fantasma (Relay Efímero)&quot;">​</a></h2><ul><li><strong>Cuándo:</strong> Adquisición de activos de alto valor o pagos sensibles de I+D.</li><li><strong>Proceso:</strong><ol><li>El agente genera un par de llaves burner efímero.</li><li>Una transferencia protegida interna fondea al burner.</li><li>El burner ejecuta el pago final.</li><li>Las llaves del burner se destruyen.</li></ol></li><li><strong>Privacidad:</strong> Desacoplamiento total. No existe vínculo on-chain entre la Tesorería del Agente y el Vendedor.</li><li><strong>Costo:</strong> Alto (Requiere dos transacciones y gas adicional).</li></ul><h2 id="nivel-4-optimizado-modo-yield" tabindex="-1">Nivel 4: Optimizado (Modo Yield) <a class="header-anchor" href="#nivel-4-optimizado-modo-yield" aria-label="Permalink to &quot;Nivel 4: Optimizado (Modo Yield)&quot;">​</a></h2><ul><li><strong>Cuándo:</strong> Se detecta liquidez ociosa.</li><li><strong>Proceso:</strong> El agente retira fondos del Riel Protegido y los deposita en Kamino Lending.</li><li><strong>Impacto:</strong> Cubre automáticamente la &quot;Tasa de Quema&quot; (Burn Rate) operativa del agente.</li></ul>',10)])])}const p=o(r,[["render",n]]);export{m as __pageData,p as default};
